class Solution(object):
    def leastBricks(self, wall):
        from collections import defaultdict
        edge_count = defaultdict(int)
        for row in wall:
            pos = 0
            for i in range(len(row) - 1):
                pos += row[i]
                edge_count[pos] += 1
        if not edge_count:
            return len(wall)
        max_edges = max(edge_count.values())
        return len(wall) - max_edges
